// Lista de agentes del mercado mayorista XM (Sinergox).
// XM cambia su schema periódicamente; este nodo es tolerante a múltiples variantes.
// Estrategia: parse estructurado (ListEntities 2025+ y Values legacy) + walker recursivo como fallback.
// PATCH: timeout 8s + safeParse (XM a veces devuelve texto plano con HTTP 200).

const XM_BASE = 'https://servapibi.xm.com.co';
const REQUEST_TIMEOUT_MS = 8000;
const now = new Date();
const end = now;
const start = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
const isoDate = d => d.toISOString().slice(0, 10);

const safeParse = (raw) => {
  if (raw == null) return { __plainText: '' };
  if (typeof raw === 'object') return raw;
  const s = String(raw).trim();
  if (!s) return { __plainText: '' };
  if (s[0] !== '{' && s[0] !== '[') return { __plainText: s };
  try { return JSON.parse(s); } catch { return { __plainText: s }; }
};

const KNOWN_ERROR_TEXTS = ['id de métrica no encontrada', 'metrica no encontrada', 'metric not found', 'no encontrado'];
const isPlainTextError = (obj) => {
  if (!obj || typeof obj !== 'object' || !('__plainText' in obj)) return false;
  const t = String(obj.__plainText).toLowerCase();
  return KNOWN_ERROR_TEXTS.some(e => t.includes(e));
};

const postXM = async (path, body) => {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `${XM_BASE}${path}`,
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'User-Agent': 'alebas-cotizador/1.0' },
    body: JSON.stringify(body),
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    timeout: REQUEST_TIMEOUT_MS,
  });
  if (r.statusCode >= 400) {
    throw new Error(`XM ${path} HTTP ${r.statusCode}`);
  }
  const parsed = safeParse(r.body);
  if (isPlainTextError(parsed)) {
    throw new Error(`XM ${path}: ${parsed.__plainText}`);
  }
  return parsed;
};

// Walker recursivo tolerante a cualquier schema
const walkAgents = (node, collected = []) => {
  if (node == null) return collected;
  if (Array.isArray(node)) { node.forEach(n => walkAgents(n, collected)); return collected; }
  if (typeof node !== 'object') return collected;
  const SIC_KEYS  = ['Id','id','Codigo','codigo','Code','code','SIC','sic','CodigoSIC','codigoSIC'];
  const NAME_KEYS = ['Nombre','nombre','Name','name','RazonSocial','razonSocial'];
  const ACT_KEYS  = ['Actividad','actividad','Actividades','actividades','Activity','activity','TipoAgente','tipoAgente'];
  const sic  = SIC_KEYS.find(k => node[k]);
  const name = NAME_KEYS.find(k => node[k]);
  const act  = ACT_KEYS.find(k => node[k]);
  if (sic || name) {
    collected.push({ sic: node[sic] || '', name: node[name] || '', activities: node[act] || '' });
  }
  for (const v of Object.values(node)) {
    if (v && typeof v === 'object') walkAgents(v, collected);
  }
  return collected;
};

let j;
let lastErr = '';
try {
  j = await postXM('/lists', { MetricId: 'ListadoAgentes', Entity: 'Sistema', StartDate: isoDate(start), EndDate: isoDate(end) });
} catch (err) {
  lastErr = err.message;
  try {
    // Fallback sin Entity
    j = await postXM('/lists', { MetricId: 'ListadoAgentes', StartDate: isoDate(start), EndDate: isoDate(end) });
  } catch (err2) {
    return [{ json: { ok: false, reason: 'xm_unreachable', detail: `Primer intento: ${lastErr}. Fallback: ${err2.message}` } }];
  }
}

const rawItems = j?.Items || j?.items || j?.data || j?.Data || j?.result || j?.Result || [];
let items = [];
if (rawItems.length) {
  const flat = [];
  for (const it of rawItems) {
    // Schema 2025+: Items[n].ListEntities[m].Values
    const listEnt = it?.ListEntities || it?.listEntities || it?.Entities || it?.entities;
    if (Array.isArray(listEnt) && listEnt.length) {
      for (const le of listEnt) {
        const v = le?.Values || le?.values || le;
        flat.push({ sic: v?.Code || v?.Id || v?.Codigo || '', name: v?.Name || v?.Nombre || '', activities: v?.Activity || v?.Actividad || '' });
      }
    } else {
      const v = it?.Values || it?.values || it;
      flat.push({ sic: v?.Id || v?.Codigo || v?.Code || it?.Id || '', name: v?.Nombre || v?.Name || it?.Name || '', activities: v?.Actividad || v?.Actividades || v?.Activity || '' });
    }
  }
  items = flat;
}

// Fallback walker si no hubo resultados estructurados
if (!items.some(a => a.sic || a.name)) {
  items = walkAgents(j);
  if (!items.length) {
    return [{ json: { ok: false, reason: 'xm_schema_drift', detail: 'Sin agentes en ningún schema conocido', sample: j } }];
  }
}

// Deduplicar
const seen = new Set();
items = items.filter(a => {
  const key = a.sic || a.name;
  if (!key || seen.has(key)) return false;
  seen.add(key); return true;
});

const filtered = items.filter(a => /D|OR|distribuid|comercial/i.test(a.activities || ''));
const operators = filtered.length ? filtered : items.filter(a => a.name || a.sic);

return [{ json: {
  ok: true,
  items,
  operators,
  total: items.length,
  activityFilterWorked: filtered.length > 0,
  syncedAt: new Date().toISOString(),
  source: 'XM ListadoAgentes',
} }];
